var _ INotificationManager = (*notificationManagerStubWrapper)(nil)

// NewNotificationManagerStub creates a server-side INotificationManager wrapping the given
// server implementation. The returned value satisfies INotificationManager
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewNotificationManagerStub(
	impl INotificationManagerServer,
) INotificationManager {
	wrapper := &notificationManagerStubWrapper{impl: impl}
	stub := &NotificationManagerStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
